// ── Regex Patterns ──────────────────────────────────────────────────────────
const REGEX_PAN = /\b[3-6]\d{3}[-\s]?\d{4}[-\s]?\d{4}[-\s]?\d{1,7}\b/g;
const REGEX_IBAN = /\b([A-Z]{2})(\d{2})\s?([A-Z0-9]{4}\s?){1,7}([A-Z0-9]{1,4})\b/g;
const REGEX_EMAIL = /\b[A-Za-z0-9._%+\-]+@[A-Za-z0-9.\-]+\.[A-Za-z]{2,}\b/g;
const REGEX_PHONE = /(?<!\d)(\+?1?\s?)?(\(?\d{3}\)?[\s.\-]?)(\d{3}[\s.\-]?\d{4})(\s?(ext|x)\.?\s?\d{1,5})?(?!\d)/g;
const REGEX_SSN_HYPHEN = /\b(?!000|666|9\d{2})([0-8]\d{2})[-\s](?!00)(\d{2})[-\s](?!0000)(\d{4})\b/g;

const SSN_CONTEXT_TRIGGERS = [
  "ssn", "social security", "social sec", "tin", "taxpayer", 
  "itin", "national id", "nationalid", "national_id", "tax id", 
  "taxid", "sin", "nino", "national insurance"
];

// ── Validation Algorithms ───────────────────────────────────────────────────
function luhnCheck(raw) {
  const digits = raw.replace(/\D/g, "");
  if (digits.length < 13 || digits.length > 19) return false;
  let sum = 0;
  let double = false;
  for (let i = digits.length - 1; i >= 0; i--) {
    let digit = parseInt(digits[i], 10);
    if (double) {
      digit *= 2;
      if (digit > 9) digit -= 9;
    }
    sum += digit;
    double = !double;
  }
  return sum % 10 === 0;
}

function ibanCheck(raw) {
  const iban = raw.replace(/\s/g, "").toUpperCase();
  if (iban.length < 15 || iban.length > 34) return false;
  const rearranged = iban.slice(4) + iban.slice(0, 4);
  const numeric = rearranged.split("").map((ch) => {
    const code = ch.charCodeAt(0);
    return code >= 65 && code <= 90 ? (code - 55).toString() : ch;
  }).join("");

  let remainder = BigInt(0);
  const chunks = numeric.match(/.{1,9}/g) || [];
  for (const chunk of chunks) {
    let multiplier = BigInt(1);
    for(let i = 0; i < chunk.length; i++) multiplier *= BigInt(10);
    remainder = ((remainder * multiplier) + BigInt(chunk)) % BigInt(97);
  }
  return remainder === BigInt(1);
}

// ── Format-Preserving Masking Functions ─────────────────────────────────────
function maskPAN(pan) {
  const digits = pan.replace(/\D/g, "");
  const sep = pan.includes(" ") ? " " : pan.includes("-") ? "-" : "";
  const masked = digits.split("").map((d, i) => (i < 6 || i >= digits.length - 4) ? d : "*").join("");
  if (!sep) return masked;
  const groups = [];
  for (let i = 0; i < masked.length; i += 4) {
    groups.push(masked.slice(i, i + 4));
  }
  return groups.join(sep);
}

function maskIBAN(iban) {
  const spaces = [];
  const stripped = iban.split("").filter((ch, i) => {
    if (ch === " ") { spaces.push(i); return false; }
    return true;
  }).join("");
  const reveal_start = 4;
  const reveal_end = stripped.length - 4;
  const masked = stripped.split("").map((ch, i) => (i < reveal_start || i >= reveal_end) ? ch : "*").join("");
  let result = masked;
  let offset = 0;
  for (const pos of spaces) {
    result = result.slice(0, pos + offset) + " " + result.slice(pos + offset);
    offset++;
  }
  return result;
}

function maskEmail(email) {
  const atIdx = email.lastIndexOf("@");
  if (atIdx < 1) return "***@***.***";
  const local = email.slice(0, atIdx);
  const domain = email.slice(atIdx + 1);
  const maskedLocal = local[0] + "***";
  const dotIdx = domain.lastIndexOf(".");
  const tld = dotIdx >= 0 ? domain.slice(dotIdx) : "";
  const maskedDomain = "***" + tld;
  return `${maskedLocal}@${maskedDomain}`;
}

function maskPhone(phone) {
  const digits = phone.replace(/\D/g, "");
  const maskedDigits = digits.split("").map((d, i) => (i >= digits.length - 2 ? d : "*")).join("");
  let digitIndex = 0;
  return phone.split("").map((ch) => {
    if (/\d/.test(ch)) return maskedDigits[digitIndex++];
    return ch;
  }).join("");
}

function maskSSN(ssn) {
  const sep = ssn.includes("-") ? "-" : ssn.includes(" ") ? " " : "";
  const digits = ssn.replace(/\D/g, "");
  const masked = digits.split("").map((d, i) => (i >= digits.length - 4 ? d : "*")).join("");
  if (!sep) return masked;
  return `${masked.slice(0, 3)}${sep}${masked.slice(3, 5)}${sep}${masked.slice(5)}`;
}

// ── Core String Redaction Pipeline ──────────────────────────────────────────
function _redactString(input, opts, context = input) {
  let result = input;
  const counts = {};
  const increment = (type, n = 1) => { counts[type] = (counts[type] || 0) + n; };

  if (opts.redactCreditCards) {
    result = result.replace(REGEX_PAN, (match) => {
      if (!luhnCheck(match)) return match;
      increment("CREDIT_CARD_PAN");
      return maskPAN(match);
    });
    REGEX_PAN.lastIndex = 0;
  }

  if (opts.redactIBANs) {
    result = result.replace(REGEX_IBAN, (match) => {
      if (!ibanCheck(match)) return match;
      increment("IBAN");
      return maskIBAN(match);
    });
    REGEX_IBAN.lastIndex = 0;
  }

  if (opts.redactEmails) {
    result = result.replace(REGEX_EMAIL, (match) => {
      increment("EMAIL");
      return maskEmail(match);
    });
    REGEX_EMAIL.lastIndex = 0;
  }

  if (opts.redactPhones) {
    result = result.replace(REGEX_PHONE, (match) => {
      const digitCount = (match.match(/\d/g) || []).length;
      if (digitCount < 7) return match;
      increment("PHONE");
      return maskPhone(match);
    });
    REGEX_PHONE.lastIndex = 0;
  }

  if (opts.redactSSNs) {
    result = result.replace(REGEX_SSN_HYPHEN, (match) => {
      increment("SSN_NATIONAL_ID");
      return maskSSN(match);
    });
    REGEX_SSN_HYPHEN.lastIndex = 0;

    const contextLower = context.toLowerCase();
    const hasSSNContext = SSN_CONTEXT_TRIGGERS.some((t) => contextLower.includes(t));

    if (hasSSNContext) {
      result = result.replace(
        /(?<!\d)(?!000|666|9\d{2})([0-8]\d{2})(?!00)(\d{2})(?!0000)(\d{4})(?!\d)/g,
        (match) => {
          increment("SSN_NATIONAL_ID");
          return maskSSN(match);
        }
      );
    }
  }

  return { result, counts };
}

// ── Deep JSON Traversal ─────────────────────────────────────────────────────
function _traverseAndRedact(value, path, opts, events) {
  if (typeof value === "string") {
    const { result, counts } = _redactString(value, opts);
    for (const [type, count] of Object.entries(counts)) {
      if (count > 0) events.push({ type, path, count });
    }
    return result;
  }

  if (Array.isArray(value)) {
    return value.map((item, idx) => _traverseAndRedact(item, `${path}[${idx}]`, opts, events));
  }

  if (value !== null && typeof value === "object") {
    const sanitised = {};
    for (const [key, child] of Object.entries(value)) {
      sanitised[key] = _traverseAndRedact(child, path ? `${path}.${key}` : key, opts, events);
    }
    return sanitised;
  }

  return value;
}

// ── Public API Wrapper ──────────────────────────────────────────────────────
const DEFAULT_OPTIONS = {
  redactCreditCards: true,
  redactIBANs: true,
  redactEmails: true,
  redactPhones: true,
  redactSSNs: true,
};

function redactPayload(payload, options = {}) {
  const opts = { ...DEFAULT_OPTIONS, ...options };
  const events = [];
  const sanitised = _traverseAndRedact(payload, "(root)", opts, events);
  return {
    sanitised,
    report: {
      total_redactions: events.reduce((s, e) => s + e.count, 0),
      events,
      redacted_at: new Date().toISOString(),
    },
  };
}

