// --- Helpers ---

function haversineDistance(a, b) {
  const R = 6371; // Earth radius in km
  const dLat = ((b.lat - a.lat) * Math.PI) / 180;
  const dLon = ((b.lon - a.lon) * Math.PI) / 180;
  const lat1 = (a.lat * Math.PI) / 180;
  const lat2 = (b.lat * Math.PI) / 180;
  const sinDLat = Math.sin(dLat / 2);
  const sinDLon = Math.sin(dLon / 2);
  const aVal = sinDLat * sinDLat + Math.cos(lat1) * Math.cos(lat2) * sinDLon * sinDLon;
  const c = 2 * Math.atan2(Math.sqrt(aVal), Math.sqrt(1 - aVal));
  return R * c;
}

function amountRisk(amount) {
  return Math.min((amount / CONFIG.AMOUNT_MAX) * 100, 100);
}

function geoRisk(userLoc, deviceLoc) {
  if (!userLoc || !deviceLoc) return 0;
  const dist = haversineDistance(userLoc, deviceLoc);
  return dist > CONFIG.GEO_MISMATCH_KM ? CONFIG.GEO_MISMATCH_SCORE : 0;
}

function velocityRisk(recentCount) {
  return Math.min((recentCount / CONFIG.VELOCITY_MAX_PER_HOUR) * 100, 100);
}

function deviceRisk(trustScore) {
  return 100 - trustScore;
}

function calculateRiskScore(input) {
  const w = CONFIG.WEIGHTS;
  const score =
    w.amount * amountRisk(input.amount) +
    w.geo * geoRisk(input.userLocation, input.deviceLocation) +
    w.velocity * velocityRisk(input.recentRequestCount) +
    w.device * deviceRisk(input.deviceTrustScore);
  return Math.round(score);
}

function calculateAmbiguityScore(input) {
  const intentKey = (input.intent || '').toUpperCase();
  const required = CONFIG.REQUIRED_FIELDS[intentKey] || CONFIG.REQUIRED_FIELDS.DEFAULT;

  if (required.length === 0) return 0;

  let missingCount = 0;
  for (const field of required) {
    const value = input[field];
    if (field === 'amount') {
      if (!value || value <= 0) missingCount++;
    } else if (field === 'destinationAccount' || field === 'message') {
      if (!value || typeof value !== 'string' || value.trim() === '') missingCount++;
    }
  }

  return Math.round((missingCount / required.length) * 100);
}

function determineRoute(input) {
  const risk_score = calculateRiskScore(input);
  const ambiguity_score = calculateAmbiguityScore(input);
  const intentKey = (input.intent || '').toUpperCase();

  let route;

  if (ambiguity_score > 40) {
    route = 'CLARIFICATION_LOOP';
  } else if (intentKey === 'FAQ' && risk_score < 20) {
    route = 'FLOW_FAQ';
  } else if (risk_score > 80) {
    route = 'FLOW_SECURITY';
  } else if (intentKey === 'TRANSACTION' || intentKey === 'PAYMENT_ISSUE' || intentKey === 'TRANSFER') {
    route = 'FLOW_TRANSACTION';
  } else {
    route = 'FLOW_GENERAL';
  }

  return { route, risk_score, ambiguity_score };
}

// --- Execution Loop ---

const items = $input.all();
const output = [];

for (const item of items) {
  const ct = item.json.canonical_ticket || {};
  const meta = ct.metadata || {};

  // Safely map values from previous feature engineering & rule engines
  const safeInput = {
    amount: parseFloat(ct.transaction_amount || item.json.transaction_amount) || 0,
    userLocation: meta.userLocation,
    deviceLocation: meta.deviceLocation,
    recentRequestCount: parseInt(meta.recentRequestCount, 10) || 0,
    // Default device trust to 100 (trusted) if not strictly provided by WAF/webhook to avoid false-positives
    deviceTrustScore: meta.deviceTrustScore !== undefined ? Math.min(100, Math.max(0, parseFloat(meta.deviceTrustScore))) : 100,
    intent: ct.rule_engine?.intent || 'DEFAULT',
    // Use text features regex result as fallback for destination account mapping
    destinationAccount: meta.destinationAccount || (ct.text_features?.has_account_number ? "account_detected" : undefined),    
    message: `${ct.subject || ''} ${ct.body || ''}`.trim()
  };

  // Execute triage logic
  const decision = determineRoute(safeInput);

  output.push({
    json: {
      ...item.json,
      canonical_ticket: {
        ...ct,
        routing_decision: decision
      }
    }
  });
}

return output;

/**
 * @file Business Impact & ROI Calculator
 * @version 2.1.0
 * @description Calculates financial impact and efficiency gains for automated ticket resolution.
 */

// 1. Constants & Default Configuration (Hardened)
const DEFAULTS = {
    COST_CONFIG: {
        agent_hourly_rate: 50000,
        manual_ticket_cost: 12500,
        ai_processing_cost: 2500,
        avg_resolution_time_mins: 15
    },
    CURRENCY: 'UZS'
};

try {
    const item = $input.first();
    const ct = item.json.canonical_ticket || {};

    // 2. Defensive Configuration Loading
    // Hierarchy: Workflow Config > Ticket Meta > Global Defaults
    const config = {
        ...DEFAULTS.COST_CONFIG,
        ...(ct.workflow_metadata?.config?.cost_uzs || {})
    };

    // 3. Extraction & Validation
    const isAutoResolved = ct.ticket_status === 'auto_resolved';
    const aiCost = Number(config.ai_processing_cost) || 0;
    const manualCost = Number(config.manual_ticket_cost) || 0;

    // 4. Core Logic: Financial Impact
    // Enterprise Standard: We calculate Gross Savings before ROI
    const grossSavings = isAutoResolved ? Math.max(0, manualCost - aiCost) : 0;

    // Prevent Division by Zero and handle ROI as a Ratio
    const roiPercentage = (isAutoResolved && aiCost > 0) 
        ? ((manualCost - aiCost) / aiCost) * 100 
        : 0;

    // 5. Build Structured Response
    return [{
        json: {
            ...item.json, // Preserve original root data
            canonical_ticket: {
                ...ct,
                business_impact: {
                    metrics: {
                        ai_cost_uzs: aiCost,
                        manual_cost_uzs: manualCost,
                        cost_saved_uzs: grossSavings,
                        roi_percent: parseFloat(roiPercentage.toFixed(2)),
                        time_saved_minutes: isAutoResolved ? config.avg_resolution_time_mins : 0
                    },
                    metadata: {
                        calculation_timestamp: new Date().toISOString(),
                        currency: DEFAULTS.CURRENCY,
                        config_source: ct.workflow_metadata?.config?.cost_uzs ? 'dynamic_override' : 'system_default',
                        version: "2.1.0"
                    }
                },
                data_integrity: {
                    ...ct.data_integrity,
                    last_modified: Date.now(),
                    modification_count: (ct.data_integrity?.modification_count || 0) + 1,
                    trace_id: ct.workflow_metadata?.trace_id || 'N/A'
                }
            }
        }
    }];

} catch (error) {
    // 6. Enterprise Error Handling
    // Instead of crashing, we return the item with an error flag for the next node to handle
    return [{
        json: {
            ...$input.first().json,
            error: {
                message: "Business Impact Calculation Failed",
                details: error.message,
                context: "impact_calculator_node"
            }
        }
    }];
}

