// Determine failure class logic
function determineFailureClass(g) {
    if (g.uid?.is_duplicate_event) return 'duplicate';
    const reason = g.policy?.reason || '';
    if (reason.includes('oscillation')) return 'oscillation';
    if (reason.includes('invalid_transition')) return 'invalid_transition';
    if (g.error) return 'validation_error';
    return g.policy?.decision === 'allowed' ? 'none' : 'guard_decision';
}

